sql:
SELECT t2.hdf5_name
FROM bit_sizes AS t1
JOIN datasets AS t2 ON t1.bit_size = t2.bit_size
WHERE t1.bit_size = (
  SELECT MAX(bit_size) FROM bit_sizes
);

SELECT hdf5_name, data_type
FROM datasets
WHERE dataset_id = 0;

external_knowledge:
- 'Most active users' refers to the users who have made the most comments; 
- 'Comments made on May 1, 2023' refers to comments with an updated_at timestamp starting with '2023-05-01'; 
- 'Top datasets' are the datasets with the highest number of comments.

