SELECT COUNT(DISTINCT dataset_id) 
FROM access_logs 
WHERE status = 'success';

SELECT bit_size, description
FROM bit_sizes
WHERE bit_size = (SELECT MIN(bit_size) FROM bit_sizes);

SELECT data_type
FROM datasets
WHERE created_by = 1;

SELECT dataset_id, description, data_type
FROM datasets
WHERE dataset_id = 1;
